import{_ as a,o as l,c as o,a2 as i}from"./chunks/framework.BbQrW5_t.js";const q=JSON.parse('{"title":"《复盘：对过去的事情做思维演练》读书笔记","description":"","frontmatter":{},"headers":[],"relativePath":"study/reading-notes/20260713-《复盘：对过去的事情做思维演练》读书笔记.md","filePath":"study/reading-notes/20260713-《复盘：对过去的事情做思维演练》读书笔记.md","lastUpdated":1783931283000}'),r={name:"study/reading-notes/20260713-《复盘：对过去的事情做思维演练》读书笔记.md"};function e(d,t,n,s,h,p){return l(),o("div",null,[...t[0]||(t[0]=[i(`<h1 id="《复盘-对过去的事情做思维演练》读书笔记" tabindex="-1">《复盘：对过去的事情做思维演练》读书笔记 <a class="header-anchor" href="#《复盘-对过去的事情做思维演练》读书笔记" aria-label="Permalink to &quot;《复盘：对过去的事情做思维演练》读书笔记&quot;">​</a></h1><p><strong>书籍信息</strong></p><ul><li>书名：复盘：对过去的事情做思维演练</li><li>作者：陈中</li><li>出版社：机械工业出版社</li><li>出版时间：2013年8月</li><li>分类：💼 职场发展</li></ul><p><strong>阅读日期</strong>：2026年7月13日</p><hr><h2 id="一、核心观点" tabindex="-1">一、核心观点 <a class="header-anchor" href="#一、核心观点" aria-label="Permalink to &quot;一、核心观点&quot;">​</a></h2><h3 id="_1-复盘的本质定义" tabindex="-1">1. 复盘的本质定义 <a class="header-anchor" href="#_1-复盘的本质定义" aria-label="Permalink to &quot;1. 复盘的本质定义&quot;">​</a></h3><p>复盘是从围棋术语引入的概念，指在头脑中对过去所做的事情重新&quot;过&quot;一遍。它不同于简单的总结，核心在于<strong>推演</strong>——通过推演这个动作，复盘不仅仅是对过去的复制呈现，而是可以对各种可能性进行探讨。</p><p>复盘包括四个阶段：</p><ul><li><strong>回顾</strong>：回顾目标和过程</li><li><strong>反思</strong>：反思原因</li><li><strong>探究</strong>：探究规律</li><li><strong>提升</strong>：提升能力</li></ul><p>前三个阶段是过程，后一个阶段是结果。</p><h3 id="_2-复盘的核心价值" tabindex="-1">2. 复盘的核心价值 <a class="header-anchor" href="#_2-复盘的核心价值" aria-label="Permalink to &quot;2. 复盘的核心价值&quot;">​</a></h3><table tabindex="0"><thead><tr><th>价值维度</th><th>具体作用</th></tr></thead><tbody><tr><td>避免重复错误</td><td>被同一块石头绊倒两次是笨蛋，复盘帮助我们从错误中学习</td></tr><tr><td>固化流程</td><td>将最优应对之策固定下来，形成规范流程，如飞机起飞前的检查清单</td></tr><tr><td>校验方向</td><td>从&quot;蒙着打&quot;变成&quot;瞄着打&quot;，随时审视是否偏离目标</td></tr><tr><td>看清本质</td><td>探索问题背后的问题，直到事物本质</td></tr><tr><td>发现新知</td><td>复盘是知识组成的重要来源，能发现新的信息和规律</td></tr><tr><td>提升品性</td><td>复盘次数多了，人会变得深思沉稳，胜不骄败不馁</td></tr></tbody></table><h3 id="_3-复盘的三种类型" tabindex="-1">3. 复盘的三种类型 <a class="header-anchor" href="#_3-复盘的三种类型" aria-label="Permalink to &quot;3. 复盘的三种类型&quot;">​</a></h3><ul><li><strong>自我复盘</strong>：随时随地可进行，是最简单最具操作性的方式。关键在于真诚，不能自我欺骗，要&quot;无情&quot;地复盘自己。</li><li><strong>团队复盘</strong>：需要专门的场地和时间，是讨论会而非宣讲会。需要好的复盘文化支撑。</li><li><strong>复盘他人</strong>：用他山之石攻玉，不花成本就获得成长。最重要的是复盘标杆。</li></ul><h3 id="_4-复盘的两种方法" tabindex="-1">4. 复盘的两种方法 <a class="header-anchor" href="#_4-复盘的两种方法" aria-label="Permalink to &quot;4. 复盘的两种方法&quot;">​</a></h3><p><strong>情境重现法</strong>： 重现三种&quot;场&quot;——信息场（有什么）、思维场（是什么）、情绪场（为什么）。适合刚开始复盘时使用。</p><p><strong>关键点法则</strong>：</p><ul><li>正向关键点：按时间顺序寻找里程碑节点</li><li>逆向关键点：确定关键成功因素后复盘</li></ul><p>适合复盘熟练后使用，尤其是复盘他人时。</p><h3 id="_5-复盘的三个核心问题" tabindex="-1">5. 复盘的三个核心问题 <a class="header-anchor" href="#_5-复盘的三个核心问题" aria-label="Permalink to &quot;5. 复盘的三个核心问题&quot;">​</a></h3><p>复盘时要谈论的内容可通过三个问题清晰：</p><ol><li><strong>现在情况如何</strong>？——事实呈现，不夹杂观点</li><li><strong>当初是怎么决定的</strong>？——审视事情如何确定、根据什么确定、执行如何</li><li><strong>让我们再审视下思考的前提</strong>？——检查动机是否纯粹、对本质的理解是否正确</li></ol><h3 id="_6-柳传志环-pdf方法" tabindex="-1">6. 柳传志环：PDF方法 <a class="header-anchor" href="#_6-柳传志环-pdf方法" aria-label="Permalink to &quot;6. 柳传志环：PDF方法&quot;">​</a></h3><p>做事的完整闭环：</p><ul><li><strong>P（Preview）</strong>：沙盘推演——事前演练</li><li><strong>D（Do）</strong>：执行——做的过程</li><li><strong>F（FuPan）</strong>：复盘——事后反思</li></ul><hr><h2 id="二、启发思考" tabindex="-1">二、启发思考 <a class="header-anchor" href="#二、启发思考" aria-label="Permalink to &quot;二、启发思考&quot;">​</a></h2><h3 id="关于人生发展" tabindex="-1">关于人生发展 <a class="header-anchor" href="#关于人生发展" aria-label="Permalink to &quot;关于人生发展&quot;">​</a></h3><p><strong>思考1：向自己学习是最重要的学习途径</strong></p><p>书中引用孙陶然的话：&quot;人学习有三种途径，一种是自书本上学前人的知识，一种是自身边的人身上学其先进，一种是向自己过去的经验和教训学习。其中最重要的学习途径是向自己学习。&quot;</p><p>柳传志说：向书本学、向别人学，只占到30%，剩下70%都是向自己学。向自己学的关键，就是复盘。</p><p>这对17年软件从业的我触动很大——我一直在向外学习新技术、新框架，却很少系统地复盘自己的项目经历。那些成功项目的真正原因是什么？那些失败项目的根源在哪里？我从未真正&quot;推演&quot;过。</p><p><strong>思考2：复盘是自我品性的修炼工具</strong></p><p>冯仑的万通每年9月13日设立&quot;反省日&quot;，这已成为万通的生存密码。冯仑说：&quot;反省后知差距、知方向、知动力、知努力。&quot;</p><p>复盘做多了，人会变得沉稳，不会轻率轻浮。这让我联想到曾国藩的例子——他通过一年的在家复盘，认识到自己以前&quot;刚烈太甚&quot;，复出后采用&quot;柔弱胜刚强&quot;的方式，最终成就&quot;完人&quot;。</p><p><strong>思考3：人生需要定期复盘</strong></p><p>联想的经验是：</p><ul><li>小事及时复盘</li><li>大事阶段性复盘</li><li>事后全面复盘</li></ul><p>人生也应该如此。每天睡前快速复盘当天得失，每个季度复盘人生阶段性目标，每年做一次全面的人生盘点。</p><h3 id="关于家庭关系" tabindex="-1">关于家庭关系 <a class="header-anchor" href="#关于家庭关系" aria-label="Permalink to &quot;关于家庭关系&quot;">​</a></h3><p><strong>思考4：复盘可以应用于家庭教育</strong></p><p>书中提到罗伯特·西奥迪尼复盘自己被童子军&quot;套路&quot;买巧克力的经历，发现了&quot;互惠原理&quot;和&quot;拒绝-退让策略&quot;。这说明复盘可以用于理解人际互动。</p><p>在与妻子、孩子的互动中，我是否可以复盘？比如一次争吵后，复盘当时的信息场、思维场、情绪场——我当时是怎么想的？她当时是什么情绪？为什么会发展到争吵？</p><p><strong>思考5：家庭决策需要复盘</strong></p><p>书中强调&quot;让我们再审视下思考的前提&quot;。家庭中的重大决策（买房、孩子教育方向、职业变动）往往基于某些隐含假设。定期复盘这些假设是否还成立，可以避免方向性错误。</p><h3 id="关于事业发展" tabindex="-1">关于事业发展 <a class="header-anchor" href="#关于事业发展" aria-label="Permalink to &quot;关于事业发展&quot;">​</a></h3><p><strong>思考6：复盘是管理者的核心能力</strong></p><p>联想把复盘定为三大方法论之首，柳传志说&quot;复盘至关重要&quot;。作为技术总监/项目经理，复盘应该成为我的管理习惯。</p><p>项目结束后复盘、阶段性复盘、关键节点复盘——这些都可以帮助团队避免重复错误，固化成功经验。</p><p><strong>思考7：团队复盘需要正确的文化</strong></p><p>书中指出团队复盘失败的两个极端：要么无人发言变成静默会，要么变成责任推卸的争论会。</p><p>根源在于复盘文化：</p><ul><li>不能流于形式走过场</li><li>不能是秋后算账的大会</li><li>不能是寻找替罪羊批斗的大会</li><li>应该是探寻真相求知求真的大会</li></ul><p><strong>思考8：复盘揭示问题背后的问题</strong></p><p>书中TCL并购汤姆逊的案例启发深刻：表面上看是彩电技术趋势判断错误、法国人事成本高、文化难以融合，但真正的问题是&quot;发心不对&quot;——动机是成为世界第一彩电生产商，而不是为消费者提供更好的产品。</p><p>这让我反思：我做技术决策的动机是什么？是为了证明自己正确？还是为了解决问题？</p><h3 id="关于小孩子教育" tabindex="-1">关于小孩子教育 <a class="header-anchor" href="#关于小孩子教育" aria-label="Permalink to &quot;关于小孩子教育&quot;">​</a></h3><p><strong>思考9：教会孩子复盘是送给他们的人生礼物</strong></p><p>复盘是一种学习能力。如果从小养成复盘习惯，孩子就能从自己的经历中学习，而不是一遍遍交学费。</p><p>书中提到阿九晕倒撞墙后复盘出：呕吐头晕时要保持姿势不变，等完全清醒。这种从个人经历提炼规律的能力，正是孩子需要的。</p><p><strong>思考10：复盘培养孩子的元认知能力</strong></p><p>复盘要求审视&quot;当初是怎么决定的&quot;和&quot;思考的前提&quot;，这正是元认知——对自己思维的思考。</p><p>教孩子问自己：</p><ul><li>我当时为什么这么想？</li><li>我的想法是对的吗？</li><li>有没有其他可能性？</li></ul><hr><h2 id="三、专属建议" tabindex="-1">三、专属建议 <a class="header-anchor" href="#三、专属建议" aria-label="Permalink to &quot;三、专属建议&quot;">​</a></h2><p>结合我17年软件开发经验、技术总监/项目管理/部门经理角色、带过20+人项目和30+人部门的背景，以及两个孩子的父亲身份：</p><h3 id="对事业发展的建议" tabindex="-1">对事业发展的建议 <a class="header-anchor" href="#对事业发展的建议" aria-label="Permalink to &quot;对事业发展的建议&quot;">​</a></h3><p><strong>建议1：建立项目复盘制度</strong></p><p>作为带过多个项目的管理者，我深知项目中的教训往往被遗忘，下次项目重犯同样错误。建议：</p><ul><li>每个项目结束后召开正式复盘会</li><li>重要节点做阶段性复盘</li><li>形成复盘文档归档，作为知识库</li><li>复盘结论固化到流程中</li></ul><p>具体执行：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>复盘文档模板：</span></span>
<span class="line"><span>1. 项目目标与实际结果对比</span></span>
<span class="line"><span>2. 关键里程碑回顾</span></span>
<span class="line"><span>3. 成功点分析（是能力还是运气？）</span></span>
<span class="line"><span>4. 问题点分析（根本原因是什么？）</span></span>
<span class="line"><span>5. 规律总结（可复用的经验）</span></span>
<span class="line"><span>6. 流程改进建议</span></span></code></pre></div><p><strong>建议2：复盘团队管理风格</strong></p><p>书中曾国藩的案例启发：他通过复盘发现自己&quot;刚烈太甚&quot;，复出后采用更柔性的方式，最终成就大业。</p><p>我作为技术总监，应该复盘：</p><ul><li>与下属沟通的方式是否有效？</li><li>决策时是否充分听取意见？</li><li>有没有把自己的想法强加于人？</li><li>团队的士气问题根源在哪里？</li></ul><p><strong>建议3：复盘技术决策</strong></p><p>软件开发中技术选型决策至关重要。复盘框架：</p><ul><li>当初为什么选择这个技术栈？</li><li>支撑决策的假设还成立吗？（如性能要求、团队能力）</li><li>实际执行效果如何？</li><li>如果重来会怎么选？</li></ul><p><strong>建议4：用复盘审视职业困惑</strong></p><p>书中强调&quot;让我们再审视下思考的前提&quot;。我因家庭和身体精力原因想了解其他行业，这是决策前提。需要复盘：</p><ul><li>我的疲惫是来自工作强度，还是工作方式？</li><li>换行业真的能解决问题，还是逃避？</li><li>我的核心竞争力是什么？能否迁移？</li><li>我真正想要的是什么？</li></ul><h3 id="对家庭关系的建议" tabindex="-1">对家庭关系的建议 <a class="header-anchor" href="#对家庭关系的建议" aria-label="Permalink to &quot;对家庭关系的建议&quot;">​</a></h3><p><strong>建议5：建立家庭复盘仪式</strong></p><p>借鉴冯仑的万通反省日，可以：</p><ul><li>每周一次家庭小复盘：本周家庭有什么开心事、矛盾点？</li><li>每月一次家庭月复盘：家庭目标进展如何？</li><li>每年一次家庭年度复盘：这一年家庭的变化、成就、遗憾</li></ul><p><strong>建议6：复盘与妻子的冲突</strong></p><p>每次重要冲突后，平静时复盘：</p><ul><li>信息场：当时说了什么？做了什么？</li><li>思维场：我当时是怎么想的？她当时是怎么想的？</li><li>情绪场：我是什么情绪？她是什么情绪？</li><li>前提审视：我的动机是什么？我的假设是什么？</li></ul><h3 id="对小孩子教育的建议" tabindex="-1">对小孩子教育的建议 <a class="header-anchor" href="#对小孩子教育的建议" aria-label="Permalink to &quot;对小孩子教育的建议&quot;">​</a></h3><p><strong>建议7：用复盘框架引导孩子反思</strong></p><p>不要简单说&quot;你错了&quot;，而是引导孩子复盘：</p><ul><li>&quot;你当时是怎么想的？&quot;（回顾思维）</li><li>&quot;结果怎么样？&quot;（回顾结果）</li><li>&quot;为什么会这样？&quot;（反思原因）</li><li>&quot;下次遇到这种情况怎么办？&quot;（总结规律）</li></ul><p><strong>建议8：帮孩子复盘学习过程</strong></p><p>考试后不只看分数，而是复盘：</p><ul><li>复习策略是否有效？</li><li>时间安排是否合理？</li><li>错题的根本原因是什么？</li><li>下次考试应该怎么调整？</li></ul><p><strong>建议9：复盘孩子的习惯养成</strong></p><p>孩子养成好习惯或坏习惯，背后都有原因。复盘：</p><ul><li>这个习惯是怎么形成的？</li><li>支撑这个习惯的环境因素是什么？</li><li>如何改变环境来改变习惯？</li></ul><h3 id="对人生发展的建议" tabindex="-1">对人生发展的建议 <a class="header-anchor" href="#对人生发展的建议" aria-label="Permalink to &quot;对人生发展的建议&quot;">​</a></h3><p><strong>建议10：个人复盘系统化</strong></p><p>书中孙陶然总结复盘四步骤：目标-结果、情景再现、得失分析、规律总结。</p><p>建议建立个人复盘日记系统：</p><ul><li>每日睡前3分钟复盘：今天最重要的3件事、1个教训</li><li>每周日30分钟复盘：本周目标达成情况、关键得失</li><li>每季度2小时复盘：人生目标进展、重大决策审视</li><li>每年1天复盘：全年盘点、方向校验</li></ul><hr><h2 id="四、行动计划" tabindex="-1">四、行动计划 <a class="header-anchor" href="#四、行动计划" aria-label="Permalink to &quot;四、行动计划&quot;">​</a></h2><h3 id="短期行动-1周内" tabindex="-1">短期行动（1周内） <a class="header-anchor" href="#短期行动-1周内" aria-label="Permalink to &quot;短期行动（1周内）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>序号</th><th>行动项</th><th>具体内容</th><th>完成时间</th></tr></thead><tbody><tr><td>1</td><td>阅读笔记输出</td><td>完成本读书笔记（已完成）</td><td>7月13日</td></tr><tr><td>2</td><td>团队分享</td><td>将复盘方法论分享给技术团队，每人一份本笔记要点</td><td>7月15日</td></tr><tr><td>3</td><td>项目复盘模板</td><td>设计并输出项目复盘文档模板</td><td>7月18日</td></tr><tr><td>4</td><td>个人复盘启动</td><td>开始每日睡前3分钟复盘习惯</td><td>7月14日起</td></tr></tbody></table><h3 id="中期行动-1个月内" tabindex="-1">中期行动（1个月内） <a class="header-anchor" href="#中期行动-1个月内" aria-label="Permalink to &quot;中期行动（1个月内）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>序号</th><th>行动项</th><th>具体内容</th><th>完成时间</th></tr></thead><tbody><tr><td>5</td><td>选择一个项目复盘</td><td>选取最近一个重要项目，召开正式复盘会</td><td>7月底</td></tr><tr><td>6</td><td>职业困惑深度复盘</td><td>用复盘框架审视自己的职业困惑，输出分析文档</td><td>7月20日</td></tr><tr><td>7</td><td>家庭复盘机制</td><td>与妻子沟通，建立每周家庭小复盘习惯</td><td>7月20日</td></tr><tr><td>8</td><td>孩子复盘引导</td><td>用复盘框架引导孩子复盘一次学习过程</td><td>7月底</td></tr></tbody></table><h3 id="长期行动-持续执行" tabindex="-1">长期行动（持续执行） <a class="header-anchor" href="#长期行动-持续执行" aria-label="Permalink to &quot;长期行动（持续执行）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>序号</th><th>行动项</th><th>具体内容</th><th>执行频率</th></tr></thead><tbody><tr><td>9</td><td>项目复盘制度化</td><td>所有重要项目结束后召开复盘会</td><td>每项目</td></tr><tr><td>10</td><td>季度人生复盘</td><td>每季度2小时复盘人生目标进展</td><td>每季度</td></tr><tr><td>11</td><td>年度全面复盘</td><td>每年1天全面复盘，审视人生方向</td><td>每年</td></tr><tr><td>12</td><td>复盘文档归档</td><td>建立复盘知识库，积累复盘文档</td><td>持续</td></tr></tbody></table><hr><h2 id="五、重点摘录" tabindex="-1">五、重点摘录 <a class="header-anchor" href="#五、重点摘录" aria-label="Permalink to &quot;五、重点摘录&quot;">​</a></h2><h3 id="关于复盘的定义" tabindex="-1">关于复盘的定义 <a class="header-anchor" href="#关于复盘的定义" aria-label="Permalink to &quot;关于复盘的定义&quot;">​</a></h3><blockquote><p>所谓复盘，就是在头脑中对过去所做的事情重新&quot;过&quot;一遍。它通过对过去的思维和行为进行回顾、反思和探究，实现能力的提升。复盘的关键是推演，通过推演这个动作，复盘就不仅仅是对过去的复制呈现，而是可以对各种可能性进行探讨。</p></blockquote><h3 id="关于复盘与总结的区别" tabindex="-1">关于复盘与总结的区别 <a class="header-anchor" href="#关于复盘与总结的区别" aria-label="Permalink to &quot;关于复盘与总结的区别&quot;">​</a></h3><blockquote><p>总结是静止跳跃的，复盘是动态连续的。探究中的一个重要动作，是推演，这是复盘与总结最显著的区别。</p></blockquote><h3 id="关于学习途径" tabindex="-1">关于学习途径 <a class="header-anchor" href="#关于学习途径" aria-label="Permalink to &quot;关于学习途径&quot;">​</a></h3><blockquote><p>孙陶然：我有所成就的话，一半源于天资，一半即源于复盘。人学习有三种途径，一种是自书本上学前人的知识，一种是自身边的人身上学其先进，一种是向自己过去的经验和教训学习。其中最重要的学习途径是向自己学习。</p></blockquote><h3 id="关于复盘的价值" tabindex="-1">关于复盘的价值 <a class="header-anchor" href="#关于复盘的价值" aria-label="Permalink to &quot;关于复盘的价值&quot;">​</a></h3><blockquote><p>复盘，作为一种做事方法，是个人和组织能力提升的加速器，是看清问题的透视镜，是发现答案的探测针，是新知识和新认识的发生机，是高傲自满的终结者，是错误想法和做法的纠偏仪。</p></blockquote><h3 id="关于自我复盘的要求" tabindex="-1">关于自我复盘的要求 <a class="header-anchor" href="#关于自我复盘的要求" aria-label="Permalink to &quot;关于自我复盘的要求&quot;">​</a></h3><blockquote><p>柳传志：通过复盘总结经验教训，尤其是失败的事情，要认真，不给自己留任何情面地把这个事想清楚，把事情想明白，然后就可以谋定而后动了。</p></blockquote><h3 id="关于复盘的前提审视" tabindex="-1">关于复盘的前提审视 <a class="header-anchor" href="#关于复盘的前提审视" aria-label="Permalink to &quot;关于复盘的前提审视&quot;">​</a></h3><blockquote><p>动机要纯粹，不但要&quot;公义&quot;，更要&quot;正义&quot;。公义，指的是大家的利益。正义，不是我们平常理解的那种意思，而是说，要符合事情本来的内涵。</p></blockquote><h3 id="关于团队复盘文化" tabindex="-1">关于团队复盘文化 <a class="header-anchor" href="#关于团队复盘文化" aria-label="Permalink to &quot;关于团队复盘文化&quot;">​</a></h3><blockquote><p>团队复盘，不能流于形式走过场，不能是秋后算账的大会，不能是强调客观推卸责任的大会，不能是寻找替罪羊批斗的大会，而应该是探寻真相求知求真的大会，是观点和思路交锋的大会，是验证逻辑的大会。</p></blockquote><h3 id="关于复盘他人" tabindex="-1">关于复盘他人 <a class="header-anchor" href="#关于复盘他人" aria-label="Permalink to &quot;关于复盘他人&quot;">​</a></h3><blockquote><p>所谓他山之石，可以攻玉。复盘他人，从他人做的事情中获得经验和教训，这是一种非常&quot;划得来&quot;的事情，因为所复盘的事情你并没有真正花成本去做，是别人用资源在你面前&quot;演练&quot;了一番。</p></blockquote><hr><h2 id="六、联想复盘方法论附录" tabindex="-1">六、联想复盘方法论附录 <a class="header-anchor" href="#六、联想复盘方法论附录" aria-label="Permalink to &quot;六、联想复盘方法论附录&quot;">​</a></h2><p>联想集团复盘的四个步骤：</p><ol><li><strong>回顾目标</strong>：当初的目标是什么？</li><li><strong>评估结果</strong>：现在的结果与目标对比，差距在哪里？</li><li><strong>分析原因</strong>：成功的原因是什么？失败的原因是什么？</li><li><strong>总结规律</strong>：从中总结出什么规律？如何应用到以后？</li></ol><p>复盘的&quot;五求&quot;：</p><ul><li>求真：重在实事求是</li><li>求实：重在内容和找原因</li><li>求学：重在改进和提高</li><li>求内：重在反思和自我剖析</li><li>求道：重在找到本质和规律</li></ul><p>复盘的五个误区：</p><ul><li>自己骗自己，不能无情剖析自己</li><li>流于形式，走过场</li><li>追究责任，变成批斗会</li><li>强调客观，推卸责任</li><li>太急于得出结论</li></ul><hr><p><em>本笔记基于《复盘：对过去的事情做思维演练》全书内容整理，结合个人背景进行专属思考和建议设计。</em></p>`,142)])])}const c=a(r,[["render",e]]);export{q as __pageData,c as default};
